package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

public class CSVFormatTest {

    private void setFinalField(Object target, String fieldName, Object value) throws Exception {
        Field field = CSVFormat.class.getDeclaredField(fieldName);
        field.setAccessible(true);

        // Remove final modifier from field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(field, field.getModifiers() & ~Modifier.FINAL);

        field.set(target, value);
    }

    @Test
    void testGetHeaderCommentsReturnsCloneWhenNotNull() throws Exception {
        // Create a new CSVFormat instance with headerComments set via withHeaderComments()
        CSVFormat format = CSVFormat.DEFAULT.withHeaderComments("comment1", "comment2");

        String[] originalComments = format.getHeaderComments();
        assertNotNull(originalComments);

        String[] result = format.getHeaderComments();
        assertNotNull(result);
        assertArrayEquals(originalComments, result);

        // Verify that returned array is a clone, not the same instance
        assertNotSame(originalComments, result);
    }

    @Test
    void testGetHeaderCommentsReturnsNullWhenNull() throws Exception {
        // Create a new CSVFormat instance without headerComments set
        CSVFormat format = CSVFormat.DEFAULT.withHeaderComments((Object[]) null);

        String[] result = format.getHeaderComments();
        assertNull(result);
    }
}
